INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00439', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '某直轄市驗光生公會目前有會員數462人，下列敘述何者正確？①由會員（會員代表）選舉之理事不得超', '["每年應召開會員（會員代表）大會1次，必要時得召集臨時大會", "理事、監事名額在3人 以上時，得分別互選常務理事及常務監事，其名額不得超過理事或監事總額 1/2", "得依規定就會員分布 狀況劃定區域，按其會員人數比率選出代表，召開會員代表大會  ⑤得置候補理事、候補監事，其名額不 得超過各該公會理事、監事名額1/2  ⑥常務監事在3人以上時，應互選1人為監事會召集人", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00440', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '某驗光所之驗光生在家長要求下為其4歲的小孩驗光，此驗光生依法可能受到何種處分？①於醫師、驗光', '["依醫師開具之眼鏡處方配鏡，不罰", "其情節重大者，處1個月以上1年以下停業處 分", "其情節重大者，廢止其驗光人員證書  ⑤其情節重大者，廢止其執業執照  ⑥處新臺幣1萬元以上 5萬元以下罰鍰  ⑦處新臺幣2萬元以上10萬元以下罰鍰  ⑧處新臺幣3萬元以上15萬元以下罰鍰", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00441', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關驗光所之敘述，下列何者正確？', '["申請設立驗光所之驗光生，以在法定之機構執行業務3年以上者為限", "驗光所之名稱使用、變更，應以所在地直轄市、縣（市）主管機關核准者為限", "驗光所之名稱使用與變更、申請條件、程序及設置標準，應以所在地直轄市、縣（市）主管機關定之", "驗光所之負責驗光人員因故不能執行業務時，可由具驗光人員執照者代理之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00442', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '衛生福利部不是驗光人員法之：', '["中央主管機關", "驗光人員證書之核發單位", "驗光人員執業執照之發給單位", "驗光師證書之廢止單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00443', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列有關隱形眼鏡之敘述何者正確？①日拋、月拋、季拋等拋棄式隱形眼鏡需要醫師處方  ②隱形眼鏡屬', '["角膜塑形片等客製化隱形眼鏡民眾配戴需要醫師驗配", "日戴型隱形眼鏡，第一次配戴由 醫師或驗光師服務為宜", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00444', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列團體何者最具資格可申請認可辦理驗光人員繼續教育課程與積分審查認定及採認', '["全國性之驗光人員學會，已設立滿1年，且會員中驗光執業人數達3000人以上", "全國性之驗光人員公會，已設立超過4年，且會員中全國驗光執業人數達40%以上", "全國性之驗光人員公會，已設立滿3年，且會員中全國驗光執業人數達10%", "台北市驗光人員公會，已設立滿3年，且會員中驗光執業人數達20%以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00445', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列何者不具驗光人員考試資格？①6年前被發現曾有冒名頂替公務人員考試之情事者  ②被發現3年內', '["經廢止驗光人員執業執照未滿 1 年者", "被發 現將驗光人員證照租借他人使用者", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00446', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關驗光所之規定，下列敘述何者正確？①驗光室須有明顯區隔之獨立空間，其空間之高度距離至少5公', '["驗光所收取費用須開給載明收費項目及醫囑單，應妥為保管，並至少保存3年", "驗光人員之姓名 及證書字號不得為驗光所之廣告事項", "驗光所歇業或受撤銷、廢止開業執照處分者，應將其招牌拆除 ⑤眼鏡公司（商號）內設立驗光所者，該驗光所得與眼鏡公司（商號）共用招牌", "僅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00447', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '依法規定，驗光人員停業或歇業時，下列敘述何者錯誤？', '["驗光人員死亡者，應由原發執業執照機關註銷其執業執照", "辦理停業者，應由原發給執業執照機關登記其停業日期及理由後，發還其執業執照", "驗光人員變更執業處所者，應於事實發生之日起30日內，報請原發執業執照機關核准變更登記", "辦理歇業者，應由原發給執業執照機關註銷其執業登記，並收回執業執照"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00448', 'optician', 'optician-moex-112-5e38135e', 'sub-optician-01', NULL, 'single_choice', '驗光所違反驗光人員法第 20 條規定，對執行業務之紀錄、醫師開具之照會單或醫囑單，未妥為保管規定 年限者，其罰則為何？', '["廢止執業執照處分", "處1個月以上1年以下停業處分", "處新臺幣1萬元以上5萬元以下罰鍰", "處新臺幣3萬元以上15萬元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "7d107214d300", "answer_pdf_sha1": "7e194b50ba52", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
